  1→import * as React from "react";
  2→import {
  3→  DndContext,
  4→  closestCenter,
  5→  KeyboardSensor,
  6→  PointerSensor,
  7→  useSensor,
  8→  useSensors,
  9→  DragEndEvent,
 10→} from "@dnd-kit/core";
 11→import {
 12→  arrayMove,
 13→  SortableContext,
 14→  sortableKeyboardCoordinates,
 15→  verticalListSortingStrategy,
 16→} from "@dnd-kit/sortable";
 17→import { FolderOpen } from "lucide-react";
 18→import { Sidebar, SidebarContent, SidebarMenu, useSidebar } from "@/components/ui/sidebar";
 19→import { useUIStore } from "@/shared/stores/uiStore";
 20→import { useSidebarStore } from "../store/sidebarStore";
 21→import type { AppSidebarProps } from "../model/types";
 22→import { DraggableRepository } from "./DraggableRepository";
 23→import { SidebarHeader } from "./SidebarHeader";
 24→import { SidebarFooter } from "./SidebarFooter";
 25→
 26→export function AppSidebar({
 27→  repositories,
 28→  selectedWorkspaceId,
 29→  onWorkspaceClick,
 30→  onNewWorkspace,
 31→  onAddRepository,
 32→  onCloneRepository,
 33→  onArchive,
 34→  onStatusChange,
 35→  diffStatsMap,
 36→  profile = { username: "User" },
 37→}: AppSidebarProps) {
 38→  const { state, hoverOpen, toggleSidebar } = useSidebar();
 39→  const openSettings = useUIStore((s) => s.openSettings);
 40→  const collapsedRepos = useSidebarStore((s) => s.collapsedRepos);
 41→  const toggleRepoCollapse = useSidebarStore((s) => s.toggleRepoCollapse);
 42→  const repositoryOrder = useSidebarStore((s) => s.repositoryOrder);
 43→  const setRepositoryOrder = useSidebarStore((s) => s.setRepositoryOrder);
 44→  const reorderRepositories = useSidebarStore((s) => s.reorderRepositories);
 45→
 46→  const isExpanded = state === "expanded" || hoverOpen;
 47→
 48→  // User's drag-drop order is the final word.
 49→  // Status is shown visually (badges, colors) — not by re-sorting after drag.
 50→  const orderedRepositories = React.useMemo(
 51→    () => reorderRepositories(repositories),
 52→    [repositories, repositoryOrder, reorderRepositories]
 53→  );
 54→
 55→  // 5px distance threshold: click = expand/collapse, drag = reorder
 56→  const sensors = useSensors(
 57→    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
 58→    useSensor(KeyboardSensor, {
 59→      coordinateGetter: sortableKeyboardCoordinates,
 60→    })
 61→  );
 62→
 63→  /**
 64→   * Handle drag end - reorder repositories
 65→   */
 66→  function handleDragEnd(event: DragEndEvent) {
 67→    const { active, over } = event;
 68→
 69→    if (!over || active.id === over.id) {
 70→      return;
 71→    }
 72→
 73→    const oldIndex = orderedRepositories.findIndex((r) => r.repo_id === active.id);
 74→    const newIndex = orderedRepositories.findIndex((r) => r.repo_id === over.id);
 75→
 76→    if (oldIndex === -1 || newIndex === -1) {
 77→      return;
 78→    }
 79→
 80→    // Reorder array
 81→    const reordered = arrayMove(orderedRepositories, oldIndex, newIndex);
 82→
 83→    // Save new order to store
 84→    const newOrder = reordered.map((r) => r.repo_id);
 85→    setRepositoryOrder(newOrder);
 86→  }
 87→
 88→  return (
 89→    <Sidebar variant="inset" collapsible="offcanvas" className="p-0">
 90→      <SidebarHeader
 91→        profile={profile}
 92→        onOpenSettings={openSettings}
 93→        onToggleSidebar={toggleSidebar}
 94→        isExpanded={isExpanded}
 95→      />
 96→
 97→      {/* Repositories List or Empty State */}
 98→      {repositories.length === 0 ? (
 99→        <SidebarContent className="flex h-full items-center justify-center">
100→          <div className="flex flex-col items-center gap-3 px-6 text-center">
101→            <FolderOpen className="text-text-muted/30 h-10 w-10" strokeWidth={1.5} />
102→            <div className="space-y-1">
103→              <p className="text-text-secondary text-sm font-medium">No projects yet</p>
104→              <p className="text-text-muted text-xs">Add your first project to get started</p>
105→            </div>
106→          </div>
107→        </SidebarContent>
108→      ) : (
109→        <SidebarContent className="scrollbar-hidden">
110→          <DndContext
111→            sensors={sensors}
112→            collisionDetection={closestCenter}
113→            onDragEnd={handleDragEnd}
114→          >
115→            <SortableContext
116→              items={orderedRepositories.map((r) => r.repo_id)}
117→              strategy={verticalListSortingStrategy}
118→            >
119→              <SidebarMenu className="gap-1 px-1.5 py-2">
120→                {orderedRepositories.map((repo) => (
121→                  <DraggableRepository
122→                    key={repo.repo_id}
123→                    repository={repo}
124→                    isCollapsed={collapsedRepos.has(repo.repo_id)}
125→                    selectedWorkspaceId={selectedWorkspaceId}
126→                    onToggleCollapse={() => toggleRepoCollapse(repo.repo_id)}
127→                    onWorkspaceClick={onWorkspaceClick}
128→                    onNewWorkspace={onNewWorkspace}
129→                    onArchive={onArchive}
130→                    onStatusChange={onStatusChange}
131→                    diffStatsMap={diffStatsMap}
132→                    sidebarExpanded={isExpanded}
133→                    dragDisabled={!isExpanded}
134→                  />
135→                ))}
136→              </SidebarMenu>
137→            </SortableContext>
138→          </DndContext>
139→        </SidebarContent>
140→      )}
141→
142→      <SidebarFooter onAddRepository={onAddRepository} onCloneRepository={onCloneRepository} />
143→    </Sidebar>
144→  );
145→}
