  1→import React from "react";
  2→import { match } from "ts-pattern";
  3→import { Archive, Loader2 } from "lucide-react";
  4→import NumberFlow from "@number-flow/react";
  5→
  6→import { cn } from "@/shared/lib/utils";
  7→import { useWorkingDuration, formatDuration } from "@/shared/hooks";
  8→import { PixelGrid } from "@/features/session/ui/PixelGrid";
  9→import { getDisplayStatus, STATUS_CONFIG } from "../lib/status";
 10→import type { WorkspaceItemProps } from "../model/types";
 11→import { SidebarRow, SidebarRowIconSlot } from "./SidebarRow";
 12→import { WorkflowStatusIcon } from "./WorkflowStatusIcon";
 13→import { WorkspaceStatusMenu } from "./WorkspaceStatusMenu";
 14→
 15→/**
 16→ * WorkspaceItem — Sidebar workspace row
 17→ *
 18→ * Layout:  [Left (flex-1)]  [Right]
 19→ *   Left:
 20→ *     Row 1: [Icon 20×20 | pad-left 26px] [branch name]
 21→ *     Row 2: [pad-left 26px] [directory · status]
 22→ *   Right:
 23→ *     [+additions -deletions]
 24→ *
 25→ * Icons: working → PixelGrid generating, error → red dot, unread → gold dot.
 26→ * Idle → no icon (26px indent).
 27→ *
 28→ * State: "initializing" → shimmer row with PixelGrid thinking + "Setting up..."
 29→ */
 30→export const WorkspaceItem = React.memo(function WorkspaceItem({
 31→  workspace,
 32→  isActive,
 33→  diffStats,
 34→  onClick,
 35→  onArchive,
 36→  onStatusChange,
 37→}: WorkspaceItemProps) {
 38→  const isInitializing = workspace.state === "initializing";
 39→
 40→  // Hooks must be called unconditionally (React rules of hooks)
 41→  const { duration } = useWorkingDuration({
 42→    status: workspace.session_status,
 43→    latestMessageSentAt: workspace.latest_message_sent_at,
 44→  });
 45→
 46→  // Initializing state: non-interactive row with loading animation
 47→  if (isInitializing) {
 48→    return (
 49→      <li className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
 50→        <SidebarRow
 51→          variant="workspace"
 52→          isActive={false}
 53→          aria-label="Workspace setting up"
 54→          className="pointer-events-none"
 55→        >
 56→          <div className="flex min-w-0 flex-1 animate-[shimmer_2s_ease-in-out_infinite] flex-col gap-0.5">
 57→            {/* Row 1: thinking icon + branch name (or placeholder) */}
 58→            <div className="flex min-w-0 items-center gap-1.5">
 59→              <SidebarRowIconSlot>
 60→                <PixelGrid variant="thinking" size={14} />
 61→              </SidebarRowIconSlot>
 62→              <span className="text-text-disabled truncate text-base font-normal">
 63→                {workspace.git_branch || "New workspace"}
 64→              </span>
 65→            </div>
 66→            {/* Row 2: directory · status */}
 67→            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
 68→              {workspace.slug && (
 69→                <>
 70→                  <span className="text-text-disabled truncate text-xs">{workspace.slug}</span>
 71→                  <span className="text-text-disabled text-xs">·</span>
 72→                </>
 73→              )}
 74→              <span className="text-text-muted shrink-0 text-xs">
 75→                {match(workspace.init_stage)
 76→                  .with("worktree", () => "Creating worktree...")
 77→                  .with("dependencies", () => "Installing dependencies...")
 78→                  .with("hooks", () => "Setting up environment...")
 79→                  .with("session", () => "Finalizing...")
 80→                  .otherwise(() => "Setting up...")}
 81→              </span>
 82→            </div>
 83→          </div>
 84→        </SidebarRow>
 85→      </li>
 86→    );
 87→  }
 88→
 89→  const formatTime = (timestamp: string) => {
 90→    const date = new Date(timestamp);
 91→    const now = new Date();
 92→    const diffMs = now.getTime() - date.getTime();
 93→    const diffMins = Math.floor(diffMs / 60000);
 94→    const diffHours = Math.floor(diffMins / 60);
 95→    const diffDays = Math.floor(diffHours / 24);
 96→    const diffMonths = Math.floor(diffDays / 30);
 97→
 98→    if (diffMins < 1) return "now";
 99→    if (diffMins < 60) return `${diffMins}m ago`;
100→    if (diffHours < 24) return `${diffHours}h ago`;
101→    if (diffDays < 30) return `${diffDays}d ago`;
102→    return `${diffMonths}mo ago`;
103→  };
104→
105→  const displayStatus = getDisplayStatus(workspace);
106→  const statusConfig = STATUS_CONFIG[displayStatus];
107→  // Session activity icons take priority over workflow status
108→  const hasSessionIcon =
109→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
110→
111→  const isSetupRunning = workspace.setup_status === "running";
112→  const isSetupFailed = workspace.setup_status === "failed";
113→
114→  const statusTextClass = isSetupFailed
115→    ? "text-accent-red-muted"
116→    : isSetupRunning
117→      ? "text-text-muted"
118→      : match(displayStatus)
119→          .with("working", () => "text-text-tertiary")
120→          .with("unread", () => "text-text-secondary")
121→          .with("error", () => "text-accent-red-muted")
122→          .otherwise(() => "text-text-disabled");
123→
124→  const getStatusText = (): string => {
125→    if (isSetupRunning) return "Installing...";
126→    if (isSetupFailed) return "Setup failed";
127→    if (workspace.state === "archived") return "Archived";
128→    if (!workspace.session_status) return formatTime(workspace.updated_at);
129→
130→    return match(displayStatus)
131→      .with("idle", () => formatTime(workspace.updated_at))
132→      .with("unread", () => "Needs response")
133→      .with("working", () =>
134→        duration > 0 ? formatDuration(duration, false) : STATUS_CONFIG.working.labelActive
135→      )
136→      .with("error", () => STATUS_CONFIG.error.label)
137→      .otherwise(() => statusConfig.label);
138→  };
139→
140→  const statusText = getStatusText();
141→  const showStatusDot = Boolean(workspace.slug && statusText);
142→
143→  const additions = diffStats?.additions ?? 0;
144→  const deletions = diffStats?.deletions ?? 0;
145→  const hasChanges = additions > 0 || deletions > 0;
146→
147→  const handleArchive = (e: React.MouseEvent) => {
148→    e.stopPropagation();
149→    if (onArchive) {
150→      onArchive(workspace.id);
151→    }
152→  };
153→
154→  const isArchived = workspace.state === "archived";
155→  const canArchive = !isArchived && !!onArchive;
156→  const isActiveState =
157→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
158→
159→  return (
160→    <li>
161→      <SidebarRow
162→        variant="workspace"
163→        isActive={isActive}
164→        role="button"
165→        tabIndex={0}
166→        data-workspace-id={workspace.id}
167→        className="cursor-pointer"
168→        aria-current={isActive ? "page" : undefined}
169→        aria-label={`Workspace ${workspace.git_branch} on ${workspace.slug}`}
170→        onClick={() => onClick(workspace)}
171→        onKeyDown={(e) => {
172→          if (e.key === " ") e.preventDefault();
173→        }}
174→        onKeyUp={(e) => {
175→          if (e.key === "Enter" || e.key === " ") onClick(workspace);
176→        }}
177→      >
178→        {/* Left: rows */}
179→        <div className="flex min-w-0 flex-1 flex-col gap-0.5">
180→          {/* Row 1: icon + branch name */}
181→          <div className="flex min-w-0 items-center gap-1.5">
182→            <WorkspaceStatusMenu
183→              currentStatus={workspace.status}
184→              onStatusChange={(status) => onStatusChange?.(workspace.id, status)}
185→            >
186→              <button
187→                type="button"
188→                onClick={(e) => e.stopPropagation()}
189→                className="flex h-5 w-5 shrink-0 items-center justify-center rounded transition-opacity hover:opacity-80"
190→                aria-label={`Status: ${workspace.status}`}
191→              >
192→                {hasSessionIcon ? (
193→                  match(displayStatus)
194→                    .with("working", () => <PixelGrid variant="generating" size={14} />)
195→                    .with("error", () => <span className="bg-accent-red h-2 w-2 rounded-full" />)
196→                    .otherwise(() => <span className="bg-accent-gold h-2 w-2 rounded-full" />)
197→                ) : (
198→                  <WorkflowStatusIcon status={workspace.status} size={14} />
199→                )}
200→              </button>
201→            </WorkspaceStatusMenu>
202→            <span
203→              className={cn(
204→                "truncate text-base",
205→                isActive
206→                  ? "text-text-primary font-medium"
207→                  : isActiveState
208→                    ? "text-text-primary font-normal"
209→                    : "text-text-tertiary font-normal"
210→              )}
211→            >
212→              {workspace.git_branch}
213→            </span>
214→          </div>
215→
216→          {/* Row 2: directory · status */}
217→          <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
218→            <span
219→              className={cn(
220→                "truncate text-xs",
221→                isActiveState ? "text-text-tertiary" : "text-text-disabled"
222→              )}
223→            >
224→              {workspace.slug}
225→            </span>
226→            {showStatusDot && (
227→              <span
228→                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
229→              >
230→                ·
231→              </span>
232→            )}
233→            {statusText && (
234→              <span className={cn("flex shrink-0 items-center gap-1 text-xs", statusTextClass)}>
235→                {isSetupRunning && (
236→                  <Loader2 className="h-3 w-3 animate-spin motion-reduce:animate-none" />
237→                )}
238→                {statusText}
239→              </span>
240→            )}
241→          </div>
242→        </div>
243→
244→        {/* Right: diff stats */}
245→        {hasChanges ? (
246→          <div
247→            className={cn(
248→              "flex shrink-0 items-center gap-1.5 text-xs font-medium transition-opacity",
249→              canArchive && "group-hover/sidebar-row:opacity-0"
250→            )}
251→          >
252→            {additions > 0 && (
253→              <NumberFlow
254→                value={additions}
255→                prefix="+"
256→                className={isActive ? "text-accent-green" : "text-text-muted"}
257→              />
258→            )}
259→            {deletions > 0 && (
260→              <NumberFlow
261→                value={deletions}
262→                prefix="-"
263→                className={isActive ? "text-accent-red" : "text-text-muted"}
264→              />
265→            )}
266→          </div>
267→        ) : null}
268→
269→        {/* Archive button — hover reveal */}
270→        {canArchive ? (
271→          <button
272→            type="button"
273→            onClick={handleArchive}
274→            aria-label={`Archive workspace ${workspace.git_branch}`}
275→            title="Archive workspace"
276→            className={cn(
277→              "text-text-muted hover:text-text-secondary flex h-7 w-7 items-center justify-center rounded-lg",
278→              "absolute top-1/2 right-1 -translate-y-1/2 opacity-0 transition-opacity",
279→              "group-hover/sidebar-row:opacity-100"
280→            )}
281→          >
282→            <Archive className="h-3.5 w-3.5" />
283→          </button>
284→        ) : null}
285→      </SidebarRow>
286→    </li>
287→  );
288→});
