  1→import { useState, useMemo, useCallback, useEffect, useRef, type KeyboardEvent } from "react";
  2→import { useWorkspacesByRepo } from "@/features/workspace/api";
  3→import { useWorkspaceStore } from "@/features/workspace/store";
  4→import { useUIStore } from "@/shared/stores/uiStore";
  5→import { track } from "@/platform/analytics";
  6→import {
  7→  CommandDialog,
  8→  CommandInput,
  9→  CommandList,
 10→  CommandEmpty,
 11→  CommandGroup,
 12→  CommandItem,
 13→  CommandShortcut,
 14→} from "@/components/ui/command";
 15→import { staticCommands, GROUP_LABELS, type CommandGroup as CmdGroup } from "../commands";
 16→import type { Workspace, RepoGroup } from "@/shared/types";
 17→
 18→interface CommandPaletteProps {
 19→  /** Runtime action overrides for commands that need native/mutation context */
 20→  actionOverrides?: Record<string, () => void>;
 21→}
 22→
 23→export function CommandPalette({ actionOverrides = {} }: CommandPaletteProps) {
 24→  const open = useUIStore((s) => s.commandPaletteOpen);
 25→  const closeCommandPalette = useUIStore((s) => s.closeCommandPalette);
 26→
 27→  const [search, setSearch] = useState("");
 28→  const [page, setPage] = useState<"home" | "workspace">("home");
 29→  const prevOpen = useRef(false);
 30→
 31→  // Track command palette open (not close)
 32→  useEffect(() => {
 33→    if (open && !prevOpen.current) {
 34→      track("command_palette_opened");
 35→    }
 36→    prevOpen.current = open;
 37→  }, [open]);
 38→
 39→  // Workspace data for the "Go to Workspace" search page
 40→  const workspacesQuery = useWorkspacesByRepo();
 41→  const selectWorkspace = useWorkspaceStore((s) => s.selectWorkspace);
 42→
 43→  const allWorkspaces = useMemo(() => {
 44→    if (!workspacesQuery.data) return [];
 45→    return workspacesQuery.data.flatMap((group: RepoGroup) =>
 46→      group.workspaces.map((w) => ({
 47→        ...w,
 48→        repoName: group.repo_name,
 49→      }))
 50→    );
 51→  }, [workspacesQuery.data]);
 52→
 53→  const handleOpenChange = useCallback(
 54→    (isOpen: boolean) => {
 55→      if (!isOpen) {
 56→        closeCommandPalette();
 57→        setSearch("");
 58→        setPage("home");
 59→      }
 60→    },
 61→    [closeCommandPalette]
 62→  );
 63→
 64→  const runCommand = useCallback(
 65→    (commandId: string, defaultAction: () => void) => {
 66→      closeCommandPalette();
 67→      setSearch("");
 68→      setPage("home");
 69→      const action = actionOverrides[commandId] ?? defaultAction;
 70→      action();
 71→    },
 72→    [closeCommandPalette, actionOverrides]
 73→  );
 74→
 75→  const handleWorkspaceSelect = useCallback(
 76→    (workspace: Workspace) => {
 77→      closeCommandPalette();
 78→      setSearch("");
 79→      setPage("home");
 80→      selectWorkspace(workspace.id);
 81→    },
 82→    [closeCommandPalette, selectWorkspace]
 83→  );
 84→
 85→  // Backspace on empty input navigates back from workspace page to home
 86→  const handleKeyDown = useCallback(
 87→    (e: KeyboardEvent) => {
 88→      if (page !== "home" && e.key === "Backspace" && !search) {
 89→        e.preventDefault();
 90→        setPage("home");
 91→      }
 92→    },
 93→    [page, search]
 94→  );
 95→
 96→  // Group commands for rendering
 97→  const grouped = useMemo(() => {
 98→    const groups: Record<CmdGroup, typeof staticCommands> = {
 99→      workspace: [],
100→      navigation: [],
101→      settings: [],
102→    };
103→    for (const cmd of staticCommands) {
104→      if (cmd.when && !cmd.when()) continue;
105→      groups[cmd.group].push(cmd);
106→    }
107→    return groups;
108→  }, []);
109→
110→  return (
111→    <CommandDialog open={open} onOpenChange={handleOpenChange}>
112→      <CommandInput
113→        placeholder={page === "workspace" ? "Search workspaces..." : "Type a command or search..."}
114→        value={search}
115→        onValueChange={setSearch}
116→        onKeyDown={handleKeyDown}
117→      />
118→      <CommandList>
119→        <CommandEmpty>No results found.</CommandEmpty>
120→
121→        {page === "home" && (
122→          <>
123→            {/* Go to workspace (shows when workspaces exist) */}
124→            {allWorkspaces.length > 0 && (
125→              <CommandGroup heading="Go to">
126→                <CommandItem
127→                  value="go-to-workspace"
128→                  keywords={["switch", "workspace", "jump", "select"]}
129→                  onSelect={() => {
130→                    setPage("workspace");
131→                    setSearch("");
132→                  }}
133→                >
134→                  <span className="text-sm">Go to Workspace...</span>
135→                  <CommandShortcut>{allWorkspaces.length}</CommandShortcut>
136→                </CommandItem>
137→              </CommandGroup>
138→            )}
139→
140→            {/* Static command groups */}
141→            {(Object.keys(grouped) as CmdGroup[]).map((groupKey) => {
142→              const commands = grouped[groupKey];
143→              if (commands.length === 0) return null;
144→              return (
145→                <CommandGroup key={groupKey} heading={GROUP_LABELS[groupKey]}>
146→                  {commands.map((cmd) => (
147→                    <CommandItem
148→                      key={cmd.id}
149→                      value={cmd.id}
150→                      keywords={cmd.keywords}
151→                      onSelect={() => runCommand(cmd.id, cmd.action)}
152→                    >
153→                      <cmd.icon className="mr-2 h-4 w-4 opacity-60" />
154→                      <span>{cmd.label}</span>
155→                      {cmd.shortcut && <CommandShortcut>{cmd.shortcut}</CommandShortcut>}
156→                    </CommandItem>
157→                  ))}
158→                </CommandGroup>
159→              );
160→            })}
161→          </>
162→        )}
163→
164→        {/* Workspace search page */}
165→        {page === "workspace" && (
166→          <CommandGroup heading="Workspaces">
167→            {allWorkspaces.map((ws) => (
168→              <CommandItem
169→                key={ws.id}
170→                value={`${ws.title || ws.slug} ${ws.repoName}`}
171→                onSelect={() => handleWorkspaceSelect(ws)}
172→              >
173→                <div className="flex flex-col gap-0.5">
174→                  <span className="text-sm">{ws.title || ws.slug}</span>
175→                  <span className="text-muted-foreground text-xs">
176→                    {ws.repoName}
177→                    {ws.git_branch ? ` \u00b7 ${ws.git_branch}` : ""}
178→                  </span>
179→                </div>
180→              </CommandItem>
181→            ))}
182→          </CommandGroup>
183→        )}
184→      </CommandList>
185→    </CommandDialog>
186→  );
187→}
