  1→/**
  2→ * Repository Actions Hook — repo registration, workspace creation, and git clone.
  3→ *
  4→ * Extracted from MainLayout to keep the layout component focused on
  5→ * orchestrating sidebar/content panels and mounting modals.
  6→ *
  7→ * Owns all state and logic for:
  8→ * - Opening a local project (native dialog + addRepo + auto-create workspace)
  9→ * - Cloning a GitHub repo (validate URL, git clone, register, create workspace)
 10→ * - Creating workspaces from the new-workspace modal
 11→ * - 409 conflict handling when registering a repo that already exists
 12→ * - Generation counter to prevent stale clone invocations from mutating state
 13→ */
 14→
 15→import { useState, useRef, useCallback } from "react";
 16→import { toast } from "sonner";
 17→import type { Repository } from "@/features/repository/types";
 18→import { useCreateWorkspace } from "@/features/workspace/api";
 19→import { useAddRepo } from "@/features/repository/api";
 20→import { native } from "@/platform";
 21→import { capabilities } from "@/platform/capabilities";
 22→import { getBackendUrl } from "@/shared/config/api.config";
 23→import { extractRepoNameFromUrl } from "@/shared/lib/utils";
 24→import { getErrorMessage } from "@shared/lib/errors";
 25→
 26→interface UseRepoActionsOptions {
 27→  selectWorkspace: (id: string | null) => void;
 28→  openNewWorkspaceModal: () => void;
 29→  closeNewWorkspaceModal: () => void;
 30→}
 31→
 32→export function useRepoActions({
 33→  selectWorkspace,
 34→  openNewWorkspaceModal,
 35→  closeNewWorkspaceModal,
 36→}: UseRepoActionsOptions) {
 37→  // Mutations
 38→  const createWorkspaceMutation = useCreateWorkspace();
 39→  const addRepoMutation = useAddRepo();
 40→
 41→  // New-workspace modal state
 42→  const [selectedRepoId, setSelectedRepoId] = useState("");
 43→  const [creating, setCreating] = useState(false);
 44→
 45→  // Clone modal state
 46→  const [cloning, setCloning] = useState(false);
 47→  const [showCloneModal, setShowCloneModal] = useState(false);
 48→  const [cloneError, setCloneError] = useState<string | null>(null);
 49→  const [cloneStatus, setCloneStatus] = useState<string | null>(null);
 50→
 51→  // Generation counter: prevents stale clone invocations from mutating state.
 52→  // Each call to handleCloneRepository captures its generation; if the counter
 53→  // advances (via close or a new clone), earlier invocations bail out.
 54→  const cloneGenerationRef = useRef(0);
 55→
 56→  /** Reset all clone modal state to idle. */
 57→  function resetCloneState() {
 58→    setShowCloneModal(false);
 59→    setCloneError(null);
 60→    setCloneStatus(null);
 61→    setCloning(false);
 62→  }
 63→
 64→  /** Add a repo, falling back to the existing one on 409 conflict. */
 65→  async function addRepoOrUseExisting(path: string): Promise<Repository> {
 66→    try {
 67→      return await addRepoMutation.mutateAsync(path);
 68→    } catch (err) {
 69→      const addError = err as { status?: number; details?: { details?: Repository } };
 70→      const existingRepo = addError?.details?.details;
 71→      if (addError?.status === 409 && existingRepo?.id) {
 72→        return existingRepo;
 73→      }
 74→      throw err;
 75→    }
 76→  }
 77→
 78→  /** Create a workspace for the given repo and select it. */
 79→  const createAndSelectWorkspace = useCallback(
 80→    async (repoId: string) => {
 81→      setCreating(true);
 82→      try {
 83→        const workspace = await createWorkspaceMutation.mutateAsync(repoId);
 84→        selectWorkspace(workspace.id);
 85→      } catch (error) {
 86→        selectWorkspace(null);
 87→        console.error("Error creating workspace:", error);
 88→        toast.error(getErrorMessage(error));
 89→      } finally {
 90→        setCreating(false);
 91→      }
 92→    },
 93→    [createWorkspaceMutation, selectWorkspace]
 94→  );
 95→
 96→  /** Create workspace from the new-workspace modal (validates repo selection). */
 97→  async function createWorkspaceFromModal() {
 98→    if (!selectedRepoId) {
 99→      toast.error("Please select a repository");
100→      return;
101→    }
102→    const repoIdToCreate = selectedRepoId;
103→    setSelectedRepoId("");
104→    closeNewWorkspaceModal();
105→    await createAndSelectWorkspace(repoIdToCreate);
106→  }
107→
108→  /** Handle "New Workspace" — if repoId is provided, create directly; otherwise open modal. */
109→  const handleNewWorkspace = useCallback(
110→    async (repoId?: string) => {
111→      if (repoId) {
112→        await createAndSelectWorkspace(repoId);
113→        return;
114→      }
115→      openNewWorkspaceModal();
116→    },
117→    [openNewWorkspaceModal, createAndSelectWorkspace]
118→  );
119→
120→  /** Open a local project via native file dialog. */
121→  async function handleOpenProject() {
122→    if (!capabilities.nativeFolderPicker) return;
123→    const folderPath = await native.dialog.pickFolder();
124→    if (!folderPath) return;
125→    const folderName = folderPath.split("/").pop() || folderPath;
126→    const toastId = toast.loading(`Adding "${folderName}"…`);
127→
128→    try {
129→      const repo = await addRepoOrUseExisting(folderPath);
130→      const workspace = await createWorkspaceMutation.mutateAsync(repo.id);
131→      selectWorkspace(workspace.id);
132→      toast.success(`"${repo.name}" ready`, { id: toastId });
133→    } catch (error) {
134→      console.error("Error adding repository:", error);
135→      toast.error(getErrorMessage(error), { id: toastId });
136→    }
137→  }
138→
139→  /** Clone a GitHub repository with staleness detection. */
140→  async function handleCloneRepository(githubUrl: string, targetPath: string) {
141→    // Advance generation so any in-flight clone from a previous invocation bails out.
142→    const generation = ++cloneGenerationRef.current;
143→    const isStale = () => generation !== cloneGenerationRef.current;
144→
145→    setCloning(true);
146→    setCloneError(null);
147→    setCloneStatus(null);
148→    try {
149→      const repoName = extractRepoNameFromUrl(githubUrl);
150→      if (!repoName) {
151→        setCloneError("Invalid repository URL");
152→        setCloning(false);
153→        return;
154→      }
155→
156→      let cloneTarget = targetPath;
157→      if (!cloneTarget) {
158→        // Default to ~/Developer/<repoName>
159→        const home = await native.dialog.getHomeDir();
160→        cloneTarget = `${home}/Developer/${repoName}`;
161→      } else if (!targetPath.endsWith(repoName) && !targetPath.endsWith(`${repoName}/`)) {
162→        cloneTarget = `${targetPath}/${repoName}`;
163→      }
164→
165→      // Phase 1: Git clone via backend HTTP (progress events pushed via WS)
166→      const baseUrl = await getBackendUrl();
167→      const cloneRes = await fetch(`${baseUrl}/api/repos/clone`, {
168→        method: "POST",
169→        headers: { "Content-Type": "application/json" },
170→        body: JSON.stringify({ url: githubUrl, targetPath: cloneTarget }),
171→      });
172→      if (!cloneRes.ok) {
173→        const err = await cloneRes.json().catch(() => ({ error: "Clone failed" }));
174→        throw new Error(err.error || `HTTP ${cloneRes.status}`);
175→      }
176→      if (isStale()) return;
177→
178→      // Phase 2: Register repository
179→      setCloneStatus("Adding repository...");
180→      const repo = await addRepoOrUseExisting(cloneTarget);
181→      if (isStale()) return;
182→
183→      // Phase 3: Create workspace (returns immediately as 'initializing')
184→      setCloneStatus("Setting up workspace...");
185→      const workspace = await createWorkspaceMutation.mutateAsync(repo.id);
186→      if (isStale()) return;
187→
188→      // Close modal and select workspace immediately — workspace state transitions
189→      // are pushed via WORKSPACE_PROGRESS events which invalidate React Query.
190→      resetCloneState();
191→      selectWorkspace(workspace.id);
192→      toast.success(`"${repo.name}" cloned`);
193→    } catch (error) {
194→      if (!isStale()) {
195→        console.error("Error cloning repository:", error);
196→        setCloneError(getErrorMessage(error));
197→        setCloneStatus(null);
198→      }
199→    } finally {
200→      if (!isStale()) {
201→        setCloning(false);
202→      }
203→    }
204→  }
205→
206→  /** Close clone modal and cancel any in-flight clone. */
207→  const closeCloneModal = useCallback(() => {
208→    cloneGenerationRef.current++;
209→    resetCloneState();
210→  }, []);
211→
212→  /** Create workspace from a GitHub PR or branch (extended params). */
213→  const handleNewWorkspaceFromGitHub = useCallback(
214→    async (params: {
215→      repositoryId: string;
216→      source_branch: string;
217→      pr_number?: number;
218→      pr_url?: string;
219→      pr_title?: string;
220→      target_branch?: string;
221→    }) => {
222→      setCreating(true);
223→      try {
224→        const workspace = await createWorkspaceMutation.mutateAsync(params);
225→        selectWorkspace(workspace.id);
226→      } catch (error) {
227→        selectWorkspace(null);
228→        console.error("Failed to create workspace from GitHub:", error);
229→        toast.error(getErrorMessage(error));
230→      } finally {
231→        setCreating(false);
232→      }
233→    },
234→    [createWorkspaceMutation, selectWorkspace]
235→  );
236→
237→  return {
238→    // New-workspace modal state
239→    selectedRepoId,
240→    setSelectedRepoId,
241→    creating,
242→    createWorkspaceFromModal,
243→    handleNewWorkspace,
244→    handleNewWorkspaceFromGitHub,
245→
246→    // Clone modal state
247→    showCloneModal,
248→    setShowCloneModal,
249→    cloning,
250→    cloneError,
251→    cloneStatus,
252→    closeCloneModal,
253→    handleCloneRepository,
254→
255→    // Open project (native dialog)
256→    handleOpenProject,
257→
258→    // For clearing clone errors from the modal
259→    clearCloneError: () => setCloneError(null),
260→  };
261→}
