 48→/**
 49→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 50→ * Must be rendered inside SidebarProvider to access sidebar open state.
 51→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 52→ */
 53→function SidebarResizeHandle({
 54→  onSizeChange,
 55→  onDraggingChange,
 56→}: {
 57→  onSizeChange: (size: number | null) => void;
 58→  onDraggingChange: (dragging: boolean) => void;
 59→}) {
 60→  const { open } = useSidebar();
 61→
 62→  const { handleProps, isDragging } = useResizeHandle({
 63→    onSizeChange,
 64→    enabled: open,
 65→    direction: "horizontal",
 66→    mode: "primary",
 67→    minPrimarySize: 200,
 68→    minSecondarySize: 400,
 69→  });
 70→
 71→  // Notify parent of drag state changes to disable sidebar transitions
 72→  useEffect(() => {
 73→    onDraggingChange(isDragging);
 74→  }, [isDragging, onDraggingChange]);
 75→
 76→  if (!open) return null;
 77→
 78→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 79→}
