  1→/**
  2→ * Workspace Service
  3→ *
  4→ * All data operations go through the WebSocket q:* protocol.
  5→ * Request-only reads use sendRequest, mutations use sendMutate,
  6→ * async actions use sendCommand.
  7→ */
  8→
  9→import { sendRequest, sendMutate, sendCommand } from "@/platform/ws";
 10→import type { Workspace, RepoGroup, DiffStats, FileChange } from "../types";
 11→import type { WorkspaceStatus } from "@shared/enums";
 12→import type { PRStatus, GhCliStatus, PRSummary, BranchSummary } from "@/shared/types";
 13→import type { NormalizedTask, ManifestResponse, TaskRunResponse } from "@shared/types/manifest";
 14→
 15→export type { NormalizedTask, ManifestResponse, TaskRunResponse };
 16→
 17→export const WorkspaceService = {
 18→  /**
 19→   * Fetch workspaces grouped by repository.
 20→   * Note: this is typically received via q:subscribe "workspaces" for real-time push.
 21→   * This one-shot version is used as a fallback.
 22→   */
 23→  fetchByRepo: async (state?: string): Promise<RepoGroup[]> => {
 24→    return sendRequest<RepoGroup[]>("workspaces", state ? { state } : undefined);
 25→  },
 26→
 27→  /**
 28→   * Fetch diff statistics for a workspace.
 29→   *
 30→   * Diffs are computed against origin/<parent_branch> (remote-first).
 31→   * Workspace creation fetches origin/<parent> before branching the worktree,
 32→   * so the merge-base is always a recent shared commit with upstream.
 33→   */
 34→  fetchDiffStats: async (id: string): Promise<DiffStats> => {
 35→    return sendRequest<DiffStats>("diffStats", { workspaceId: id });
 36→  },
 37→
 38→  /**
 39→   * Fetch file changes for a workspace.
 40→   *
 41→   * Returns { files, truncated, totalCount } -- truncated is true when
 42→   * the diff contains more than 1000 files (capped to prevent UI freeze).
 43→   */
 44→  fetchDiffFiles: async (
 45→    id: string
 46→  ): Promise<{ files: FileChange[]; truncated?: boolean; totalCount?: number }> => {
 47→    const result = await sendRequest<{
 48→      files: FileChange[];
 49→      truncated?: boolean;
 50→      total_count?: number;
 51→    }>("diffFiles", { workspaceId: id });
 52→    return {
 53→      files: result.files,
 54→      truncated: result.truncated ?? false,
 55→      totalCount: result.total_count ?? result.files.length,
 56→    };
 57→  },
 58→
 59→  /**
 60→   * Fetch diff for a specific file.
 61→   */
 62→  fetchFileDiff: async (
 63→    id: string,
 64→    file: string
 65→  ): Promise<{ diff: string; oldContent: string | null; newContent: string | null }> => {
 66→    const data = await sendRequest<{
 67→      diff: string;
 68→      old_content?: string | null;
 69→      new_content?: string | null;
 70→    }>("diffFile", { workspaceId: id, file });
 71→    return {
