 60→/**
 61→ * Fetch diff stats for a specific workspace
 62→ * Conditionally polls only when workspace is actively working.
 63→ *
 64→ * When `isWatched` is true (file watcher active via notify crate),
 65→ * polling is disabled — cache invalidation comes from fs:changed events.
 66→ * Falls back to 5s polling when not watched.
 67→ *
 68→ * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 69→ * against incomplete worktrees during initialization. Running git diff on
 70→ * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 71→ * cached for 30s, persisting as phantom diffs even after the workspace
 72→ * becomes ready. Guard here, not in the UI.
 73→ */
 74→export function useDiffStats(
 75→  workspaceId: string | null,
 76→  sessionStatus?: string | null,
 77→  isWatched: boolean = false,
 78→  workspaceState?: string | null
 79→) {
 80→  return useQuery({
 81→    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
 82→    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!),
 83→    enabled: !!workspaceId && workspaceState === "ready",
 84→    staleTime: 30000,
 85→    // Events handle invalidation when watched; fall back to polling otherwise
 86→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
 87→    refetchOnMount: "always",
 88→    refetchOnWindowFocus: true,
 89→  });
 90→}
 91→
 92→/**
 93→ * Fetch diff stats for all sidebar workspaces in bulk.
 94→ *
 95→ * Replaces per-item useDiffStats() in the sidebar (N hooks → 1 query).
 96→ * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 97→ * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 98→ * - Idle: no polling (staleTime 30s, refetch on window focus)
 99→ * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
100→ *
101→ * Guard: state === "ready" — initializing worktrees have incomplete git state
102→ * (missing HEAD, partial index → garbage diffs like +500K/-1M). Setup script
103→ * diffs are fine — .gitignore handles them, and `git checkout -- .` in the
104→ * init pipeline resets any tracked-file mutations from bun install.
105→ */
106→export function useBulkDiffStats(repoGroups: RepoGroup[]) {
107→  const queryClient = useQueryClient();
108→
109→  // Stable, de-duplicated IDs for query key — only ready workspaces.
110→  const workspaceIds = useMemo(() => {
111→    const ids = repoGroups.flatMap((g) =>
112→      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
113→    );
114→    return Array.from(new Set(ids)).sort();
115→  }, [repoGroups]);
116→
117→  // IDs of workspaces with active sessions — only these need polling.
118→  const workingIds = useMemo(() => {
119→    return repoGroups
120→      .flatMap((g) => g.workspaces)
121→      .filter((w) => w.state === "ready" && w.session_status === "working")
122→      .map((w) => w.id);
123→  }, [repoGroups]);
124→
125→  const hasWorkingWorkspaces = workingIds.length > 0;
126→
127→  return useQuery({
128→    queryKey: ["bulk-diff-stats", workspaceIds],
129→    enabled: workspaceIds.length > 0,
130→    staleTime: 30_000,
131→    placeholderData: keepPreviousData,
132→    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
133→    refetchOnMount: "always",
134→    refetchOnWindowFocus: true,
135→    queryFn: async () => {
136→      // Seed from per-workspace cache for workspaces we already have data for
137→      const results: Record<string, DiffStats> = {};
138→      for (const id of workspaceIds) {
139→        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
140→        if (cached) results[id] = cached;
141→      }
142→
143→      // Fetch: missing workspaces + working workspaces (need fresh data)
144→      const missingIds = workspaceIds.filter((id) => !(id in results));
145→      const idsToFetch = [...new Set([...missingIds, ...workingIds])];
146→
147→      if (idsToFetch.length === 0) return results;
148→
149→      // Parallel batches of 15 — balances throughput vs resource pressure
150→      const BATCH_SIZE = 15;
151→      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
152→        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
153→        const settled = await Promise.allSettled(
154→          batch.map((id) => WorkspaceService.fetchDiffStats(id))
155→        );
156→
157→        batch.forEach((id, j) => {
158→          if (settled[j].status === "fulfilled") {
159→            results[id] = settled[j].value;
160→            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
161→          }
162→        });
163→      }
164→
165→      return results;
166→    },
167→  });
168→}
