289→/**
290→ * Fetch PR status for a workspace.
291→ *
292→ * Gated on gh CLI being installed + authenticated (like Codex).
293→ * Polls every 30s while agent is working (to detect PR creation),
294→ * 60s while CI is pending post-session (CI runs 2-15min after push),
295→ * stops polling otherwise.
296→ */
297→export function usePRStatus(
298→  workspaceId: string | null,
299→  options?: { ghInstalled?: boolean; ghAuthenticated?: boolean; sessionStatus?: string }
300→) {
301→  const { ghInstalled = true, ghAuthenticated = true, sessionStatus } = options ?? {};
302→  return useQuery({
303→    queryKey: queryKeys.workspaces.prStatus(workspaceId || ""),
304→    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
305→    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
306→    staleTime: 10_000,
307→    refetchInterval: (query) => {
308→      // While agent is working: poll every 30s to detect PR creation/updates.
309→      if (sessionStatus === "working") return 30_000;
310→
311→      // After agent stops: CI checks typically run 2-15min. Poll every 60s
312→      // while CI is pending so the user sees updates without manual refresh.
313→      const data = query.state.data as PRStatus | null | undefined;
314→      if (data?.has_pr && data?.ci_status === "pending") return 60_000;
315→
316→      // No PR or CI resolved: stop polling. Window focus refetch handles edge cases.
317→      return false;
318→    },
319→    refetchOnWindowFocus: true,
320→  });
321→}
