494→/**
495→ * Update workspace workflow status (backlog/in-progress/in-review/done/canceled).
496→ * Optimistic: updates sidebar immediately, WS subscription confirms.
497→ */
498→export function useUpdateWorkspaceStatus() {
499→  const queryClient = useQueryClient();
500→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
501→
502→  return useMutation({
503→    mutationFn: ({ workspaceId, status }: { workspaceId: string; status: WorkspaceStatus }) =>
504→      WorkspaceService.updateStatus(workspaceId, status),
505→
506→    onMutate: async ({ workspaceId, status }) => {
507→      await queryClient.cancelQueries({ queryKey });
508→      let previousStatus: WorkspaceStatus | undefined;
509→
510→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
511→        if (!old) return old;
512→        return produce(old, (draft) => {
513→          for (const repo of draft) {
514→            const ws = repo.workspaces.find((w) => w.id === workspaceId);
515→            if (ws) {
516→              previousStatus = ws.status;
517→              ws.status = status;
518→              break;
519→            }
520→          }
521→        });
522→      });
523→
524→      return { workspaceId, previousStatus };
525→    },
526→
527→    onError: (_err, _vars, context) => {
528→      if (context?.previousStatus === undefined) return;
529→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
530→        if (!old) return old;
531→        return produce(old, (draft) => {
532→          for (const repo of draft) {
533→            const ws = repo.workspaces.find((w) => w.id === context.workspaceId);
534→            if (ws) {
535→              ws.status = context.previousStatus!;
536→              break;
537→            }
538→          }
539→        });
540→      });
541→    },
542→
543→    onSuccess: (_data, { workspaceId, status }) => {
544→      track("workspace_status_changed", { workspace_id: workspaceId, status });
545→    },
546→
547→    onSettled: () => {
548→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
549→    },
550→  });
551→}
