155→// Create workspace
156→app.post("/workspaces", async (c) => {
157→  const db = getDatabase();
158→  const {
159→    repository_id,
160→    source_branch,
161→    pr_number,
162→    pr_url,
163→    pr_title,
164→    target_branch,
165→  } = parseBody(CreateWorkspaceBody, await c.req.json());
166→
167→  const repo = getRepositoryById(db, repository_id);
168→  if (!repo) throw new NotFoundError("Repository not found");
169→
170→  const workspace_name = generateUniqueName(db);
171→  const parent_branch = source_branch || repo.git_default_branch || "main";
172→  const workspaceId = uuidv7();
173→
174→  let branchPrefix = "workspace";
175→  try {
176→    const gitUser = execSync("git config user.name", { cwd: repo.root_path!, encoding: "utf8" })
177→      .trim()
178→      .toLowerCase()
179→      .replace(/[^a-z0-9_-]/g, "-");
180→    if (gitUser) branchPrefix = gitUser;
181→  } catch {}
182→  const placeholderBranchName = `${branchPrefix}/${workspace_name}`;
183→
184→  // ─── IMPORTANT: Remote-first branch strategy ───────────────────────
185→  // We ALWAYS want worktrees branched from origin/<parent_branch>, not
186→  // local <parent_branch>. Diffs are computed against origin/<branch>
187→  // (see resolve_parent_branch in git.rs and git.service.ts). If origin
188→  // is stale, the merge-base drifts and every file since the divergence
189→  // shows as "changed" — producing hundreds of phantom file changes.
190→  //
191→  // Fetch the remote branch before creating the worktree so that:
192→  // 1. The worktree starts from the latest upstream commit
193→  // 2. Diff merge-base matches what we branched from (zero phantom changes)
194→  // 3. PRs will be clean against the upstream target
195→  //
196→  // This is a non-blocking fetch (~1-3s on a warm connection). Workspace
197→  // creation is already async (worktree add runs in a child process) and
198→  // correctness matters more here.
199→  // ───────────────────────────────────────────────────────────────────
200→  try {
201→    await execFileAsync("git", ["fetch", "origin", parent_branch], {
202→      cwd: repo.root_path!,
203→      timeout: 15000,
204→    });
205→  } catch (fetchErr) {
206→    // Non-fatal: if fetch fails (offline, no remote, etc.), fall back to
207→    // whatever local state we have. The worktree will still be created
208→    // from the local branch — diffs might be off but it's better than
209→    // blocking workspace creation entirely.
210→    console.warn(
211→      `[WORKSPACE] git fetch origin ${parent_branch} failed (continuing with local):`,
212→      fetchErr
213→    );
214→  }
215→
216→  db.prepare(
217→    `
218→    INSERT INTO workspaces (
219→      id, repository_id, slug, title, git_branch,
220→      git_target_branch, pr_url, pr_number, state, updated_at
221→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now'))
222→  `
223→  ).run(
224→    workspaceId,
225→    repository_id,
226→    workspace_name,
227→    pr_title || null,
228→    placeholderBranchName,
229→    target_branch || repo.git_default_branch || "main",
230→    pr_url || null,
231→    pr_number || null,
232→    "initializing"
233→  );
234→
235→  // Branch from origin/<parent_branch> when available (fetched above).
236→  // Falls back to local <parent_branch> if remote doesn't exist.
237→  const worktreeBase = await (async () => {
238→    try {
239→      await execFileAsync(
240→        "git",
241→        ["show-ref", "--verify", "--quiet", `refs/remotes/origin/${parent_branch}`],
242→        {
243→          cwd: repo.root_path!,
244→          timeout: 2000,
245→        }
246→      );
247→      return `origin/${parent_branch}`;
248→    } catch {
249→      return parent_branch;
250→    }
251→  })();
252→
253→  const workspacePath = path.join(repo.root_path!, ".opendevs", workspace_name);
254→
255→  // Fire-and-forget: run the init pipeline async (don't await).
256→  // Pipeline handles: worktree creation → deps install → .env copy → session creation.
257→  // Progress events flow: stdout → Electron main process → IPC events → Frontend.
258→  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
259→  initializeWorkspace({
260→    workspaceId,
261→    repositoryId: repository_id,
262→    repoRootPath: repo.root_path!,
263→    workspacePath,
264→    branchName: placeholderBranchName,
265→    worktreeBase,
266→    parentBranch: parent_branch,
267→  })
268→    .then(() => {
269→      // Workspace is ready — check for manifest setup script
270→      const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
271→      const setupCmd = manifest ? getSetupCommand(manifest) : null;
272→      if (setupCmd && manifest) {
273→        db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
274→        const setupEnv = getOpenDevsEnv(manifest, {
275→          id: workspaceId,
276→          rootPath: repo.root_path!,
277→          workspacePath,
278→        });
279→        runSetupScript(db, workspaceId, setupCmd, setupEnv, workspacePath);
280→      }
281→    })
282→    .catch((err) => {
283→      // Belt-and-suspenders: initializeWorkspace handles its own errors,
284→      // but if something truly unexpected escapes, don't leave workspace stuck.
285→      console.error("[WORKSPACE] Unhandled init pipeline error:", err);
286→      try {
287→        db.prepare(
288→          "UPDATE workspaces SET state = 'error', init_stage = 'unhandled', error_message = 'Unhandled init pipeline error' WHERE id = ? AND state = 'initializing'"
289→        ).run(workspaceId);
290→        invalidate(["workspaces", "stats"]);
291→      } catch {}
292→    });
293→
294→  const workspace = getWorkspaceForMiddleware(db, workspaceId);
295→  if (!workspace) throw new NotFoundError("Workspace not found after creation");
296→
297→  // Push immediately so clients see the workspace in 'initializing' state.
298→  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
299→  // The init pipeline will invalidate again when it transitions to 'ready'.

  1→// backend/src/services/agent/commands.ts
  2→// Business logic for q:command dispatch.
  3→//
  4→// Each command handler is a focused function that:
  5→//   1. Validates and extracts typed params
  6→//   2. Performs DB writes
  7→//   3. Triggers subscription invalidation
  8→//   4. Forwards to agent-server when needed
  9→//
 10→// The query engine (protocol layer) delegates here — it should never
 11→// contain business logic directly.
 12→
 13→import { match } from "ts-pattern";
 14→import { getDatabase } from "../../lib/database";
 15→import { getSessionRaw } from "../../db";
 16→import { writeUserMessage } from "../message-writer";
 17→import { spawnPty, writeToPty, resizePty, killPty } from "../pty.service";
 18→import { watchWorkspace, unwatchWorkspace } from "../fs-watcher.service";
 19→import { delegateToRoute } from "../route-delegate";
 20→import { persistSessionError } from "./persistence";
 21→import { invalidate } from "../query-engine";
 22→import * as agentService from "./service";
 23→import type { CommandName } from "@shared/types/query-protocol";
 24→
 25→// ---- Types ----
 26→
 27→type QueryParams = Record<string, unknown>;
 28→
 29→interface CommandResult {
 30→  commandId?: string;
 31→}
 32→
 33→// ---- Command Dispatch ----
 34→
 35→export async function runCommand(
 36→  command: CommandName,
 37→  params: QueryParams
 38→): Promise<CommandResult> {
 39→  return (
 40→    match(command)
 41→      .with("sendMessage", () => handleSendMessage(params))
 42→      .with("stopSession", () => handleStopSession(params))
 43→      // ---- PTY commands ----
 44→      .with("pty:spawn", () => {
 45→        const id = readString(params, "id");
 46→        const cmd = readString(params, "command") ?? "bash";
 47→        const args = Array.isArray(params.args) ? (params.args as string[]) : [];
 48→        const cols = readNumber(params, "cols") ?? 80;
 49→        const rows = readNumber(params, "rows") ?? 24;
 50→        const cwd = readString(params, "cwd");
 51→        if (!id) throw new Error("pty:spawn requires id");
 52→
 53→        const ptyId = spawnPty({ id, command: cmd, args, cols, rows, cwd });
 54→        return { commandId: ptyId };
 55→      })
 56→      .with("pty:write", () => {
 57→        const id = readString(params, "id");
 58→        if (!id) throw new Error("pty:write requires id");
 59→        const data = Array.isArray(params.data) ? (params.data as number[]) : undefined;
 60→        if (!data) throw new Error("pty:write requires data (number[])");
 61→
 62→        writeToPty(id, data);
 63→        return {};
 64→      })
 65→      .with("pty:resize", () => {
 66→        const id = readString(params, "id");
 67→        const cols = readNumber(params, "cols");
 68→        const rows = readNumber(params, "rows");
 69→        if (!id || cols === undefined || rows === undefined) {
 70→          throw new Error("pty:resize requires id, cols, and rows");
 71→        }
 72→
 73→        resizePty(id, cols, rows);
 74→        return {};
 75→      })
 76→      .with("pty:kill", () => {
 77→        const id = readString(params, "id");
 78→        if (!id) throw new Error("pty:kill requires id");
 79→
 80→        killPty(id);
 81→        return {};
 82→      })
 83→      // ---- File system commands ----
 84→      .with("fs:watch", async () => {
 85→        const workspacePath = readString(params, "workspacePath");
 86→        if (!workspacePath) throw new Error("fs:watch requires workspacePath");
 87→
 88→        await watchWorkspace(workspacePath);
 89→        return {};
 90→      })
 91→      .with("fs:unwatch", async () => {
 92→        const workspacePath = readString(params, "workspacePath");
 93→        if (!workspacePath) throw new Error("fs:unwatch requires workspacePath");
 94→
 95→        await unwatchWorkspace(workspacePath);
 96→        return {};
 97→      })
 98→      // ---- Git commands ----
 99→      .with("git:clone", () => {
100→        // Git clone is handled via HTTP POST /api/repos, not WS commands.
101→        // This arm exists so the exhaustive match compiles; reject at runtime.
102→        throw new Error("git:clone is not available as a WS command — use POST /api/repos instead");
103→      })
104→      // ---- Route-delegated commands ----
105→      .with("createWorkspace", async () => {
106→        const repositoryId = readString(params, "repository_id");
107→        if (!repositoryId) throw new Error("createWorkspace requires repository_id");
108→        const body: Record<string, unknown> = { repository_id: repositoryId };
109→        const sourceBranch = readString(params, "source_branch");
110→        const prUrl = readString(params, "pr_url");
111→        const prTitle = readString(params, "pr_title");
112→        const targetBranch = readString(params, "target_branch");
113→        if (sourceBranch) body.source_branch = sourceBranch;
114→        if (params.pr_number != null) body.pr_number = params.pr_number;
115→        if (prUrl) body.pr_url = prUrl;
116→        if (prTitle) body.pr_title = prTitle;
117→        if (targetBranch) body.target_branch = targetBranch;
118→        const result = (await delegateToRoute("POST", "/api/workspaces", body)) as { id?: string };
119→        return { commandId: result.id };
120→      })
121→      .with("retrySetup", async () => {
122→        const workspaceId = readString(params, "workspaceId");
123→        if (!workspaceId) throw new Error("retrySetup requires workspaceId");
124→        await delegateToRoute("POST", `/api/workspaces/${workspaceId}/retry-setup`);
125→        return {};
126→      })
127→      .with("openPenFile", async () => {
128→        const workspaceId = readString(params, "workspaceId");
129→        const filePath = readString(params, "filePath");
130→        if (!workspaceId || !filePath)
131→          throw new Error("openPenFile requires workspaceId and filePath");
132→        await delegateToRoute("POST", `/api/workspaces/${workspaceId}/open-pen-file`, {
133→          filePath,
134→        });
135→        return {};
136→      })
137→      .exhaustive()
138→  );
139→}
140→
141→// ---- sendMessage ----
142→
143→function handleSendMessage(params: QueryParams): CommandResult {
144→  const sessionId = readString(params, "sessionId");
145→  const content = readString(params, "content");
146→  const model = readString(params, "model");
147→  if (!sessionId || !content) {
148→    throw new Error("sendMessage requires sessionId and content");
149→  }
150→
151→  // 1. Persist the user message
152→  const result = writeUserMessage(sessionId, content, model);
153→  if (!result.success) throw new Error(result.error);
154→  invalidate(["workspaces", "sessions", "session", "messages", "stats"], {
155→    sessionIds: [sessionId],
156→  });
157→
158→  // 2. Forward to agent-server (fire-and-forget — ACK already sent)
159→  const agentType = (readString(params, "agentType") || "claude") as "claude" | "codex";
160→
161→  // Look up the existing agent_session_id so the SDK resumes the same
162→  // conversation rather than starting a new one.
163→  const db = getDatabase();
164→  const session = getSessionRaw(db, sessionId);
165→  const existingAgentSessionId = session?.agent_session_id ?? null;
166→
167→  if (!agentService.isConnected()) {
168→    handleAgentError(sessionId, agentType, new Error("Agent server is disconnected"));
169→    return { commandId: result.messageId };
170→  }
171→
172→  agentService
173→    .forwardTurn({
174→      sessionId,
175→      agentType,
176→      prompt: content,
177→      options: buildTurnOptions(params, model, existingAgentSessionId) as Parameters<
178→        typeof agentService.forwardTurn
179→      >[0]["options"],
180→    })
181→    .then((response) => {
182→      if (!response.accepted) {
183→        handleAgentRejection(sessionId, agentType, response.reason);
184→      }
185→    })
186→    .catch((err) => {
187→      handleAgentError(sessionId, agentType, err);
188→    });
189→
190→  return { commandId: result.messageId };
191→}
192→
193→// ---- stopSession ----
194→
195→async function handleStopSession(params: QueryParams): Promise<CommandResult> {
196→  const sessionId = readString(params, "sessionId");
197→  if (!sessionId) throw new Error("stopSession requires sessionId");
198→
199→  const db = getDatabase();
200→  const session = getSessionRaw(db, sessionId);
201→  if (!session) throw new Error("Session not found");
202→
203→  if (agentService.isConnected()) {
204→    try {
205→      await agentService.stopSession({ sessionId });
206→    } catch (err) {
207→      console.error("[CommandHandler] Failed to stop on agent-server:", err);
208→      // Still mark idle locally — best effort
209→    }
210→  }
211→
212→  db.prepare("UPDATE sessions SET status = 'idle', updated_at = datetime('now') WHERE id = ?").run(
213→    sessionId
214→  );
215→  invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
216→  return {};
217→}
218→
219→// ---- Helpers ----
220→
221→function buildTurnOptions(
222→  params: QueryParams,
223→  model: string | undefined,
224→  resume: string | null
225→): Record<string, unknown> {
226→  return {
227→    cwd: readString(params, "cwd") || "",
228→    model,
229→    maxThinkingTokens: params.maxThinkingTokens as number | undefined,
230→    maxTurns: params.maxTurns as number | undefined,
231→    turnId: readString(params, "turnId"),
232→    permissionMode: readString(params, "permissionMode"),
233→    providerEnvVars: readString(params, "providerEnvVars"),
234→    ghToken: readString(params, "ghToken"),
235→    opendevsEnv: params.opendevsEnv as Record<string, string> | undefined,
236→    additionalDirectories: params.additionalDirectories as string[] | undefined,
237→    chromeEnabled: params.chromeEnabled as boolean | undefined,
238→    strictDataPrivacy: params.strictDataPrivacy as boolean | undefined,
239→    shouldResetGenerator: params.shouldResetGenerator as boolean | undefined,
240→    resume: resume || readString(params, "resume"),
241→    resumeSessionAt: readString(params, "resumeSessionAt"),
242→  };
243→}
244→
245→function handleAgentRejection(sessionId: string, agentType: string, reason?: string): void {
246→  const msg = reason || "Agent rejected the message";
247→  console.error(`[CommandHandler] Agent rejected sendMessage for session=${sessionId}: ${msg}`);
248→  persistSessionError({
249→    type: "session.error",
250→    sessionId,
251→    agentType: agentType as "claude",
252→    error: msg,
253→    category: "internal",
254→  });
255→  invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
256→}
257→
258→function handleAgentError(sessionId: string, agentType: string, err: unknown): void {
259→  const errorMsg = err instanceof Error ? err.message : String(err);
260→  console.error("[CommandHandler] Failed to forward to agent-server:", errorMsg);
261→  persistSessionError({
262→    type: "session.error",
263→    sessionId,
264→    agentType: agentType as "claude",
265→    error: `Agent server communication failed: ${errorMsg}`,
266→    category: "internal",
267→  });
268→  invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
269→}
270→
271→function readString(params: QueryParams, key: string): string | undefined {
272→  const value = params[key];
273→  return typeof value === "string" ? value : undefined;
274→}
275→
276→function readNumber(params: QueryParams, key: string): number | undefined {
277→  const value = params[key];
278→  return typeof value === "number" ? value : undefined;
279→}
