  toggleCommandPalette: () => void;

  // Actions - Settings view
  openSettings: () => void;
  closeSettings: () => void;
  setActiveSettingsSection: (section: SettingsSection) => void;

  closeAllModals: () => void;
}

export const useUIStore = create<UIState>()(
  devtools(
    (set, get) => ({
      // Initial state
      showNewWorkspaceModal: false,
      newWorkspaceMode: "default" as NewWorkspaceMode,
      showSystemPromptModal: false,
      commandPaletteOpen: false,
      settingsOpen: false,
      activeSettingsSection: "general" as SettingsSection,

      // Modal actions
      openNewWorkspaceModal: (mode: NewWorkspaceMode = "default") =>
        set(
          { showNewWorkspaceModal: true, newWorkspaceMode: mode },
          false,
          "ui/openNewWorkspaceModal"
        ),

      closeNewWorkspaceModal: () =>
        set(
          { showNewWorkspaceModal: false, newWorkspaceMode: "default" },
          false,
          "ui/closeNewWorkspaceModal"
        ),

      openSystemPromptModal: () =>
        set({ showSystemPromptModal: true }, false, "ui/openSystemPromptModal"),

      closeSystemPromptModal: () =>
        set({ showSystemPromptModal: false }, false, "ui/closeSystemPromptModal"),

      // Command palette actions
      openCommandPalette: () => set({ commandPaletteOpen: true }, false, "ui/openCommandPalette"),

      closeCommandPalette: () =>
        set({ commandPaletteOpen: false }, false, "ui/closeCommandPalette"),

      toggleCommandPalette: () =>
        set(
          (state) => ({ commandPaletteOpen: !state.commandPaletteOpen }),
          false,
          "ui/toggleCommandPalette"
        ),

      // Settings view actions
      openSettings: () => set({ settingsOpen: true }, false, "ui/openSettings"),

      closeSettings: () => set({ settingsOpen: false }, false, "ui/closeSettings"),

      setActiveSettingsSection: (section) =>
        set({ activeSettingsSection: section }, false, "ui/setActiveSettingsSection"),

      closeAllModals: () =>
        set(
          {
            showNewWorkspaceModal: false,
            newWorkspaceMode: "default" as NewWorkspaceMode,
            showSystemPromptModal: false,
            commandPaletteOpen: false,
            settingsOpen: false,
          },
          false,
          "ui/closeAllModals"
        ),
    }),
    {
      name: "ui-store",
      enabled: import.meta.env.DEV,
    }
  )
);

/**
 * Stable Actions - Call from anywhere without causing re-renders
 *
 * Use these when:
 * - Calling from event handlers or callbacks
 * - Calling from IPC event listeners
 * - Calling from keyboard shortcuts
 * - You don't need to subscribe to state changes
 */
export const uiActions = {
  openNewWorkspaceModal: () => useUIStore.getState().openNewWorkspaceModal(),
  closeNewWorkspaceModal: () => useUIStore.getState().closeNewWorkspaceModal(),
  openSystemPromptModal: () => useUIStore.getState().openSystemPromptModal(),
  closeSystemPromptModal: () => useUIStore.getState().closeSystemPromptModal(),
  openSettings: () => useUIStore.getState().openSettings(),
  closeSettings: () => useUIStore.getState().closeSettings(),
  openCommandPalette: () => useUIStore.getState().openCommandPalette(),
  closeCommandPalette: () => useUIStore.getState().closeCommandPalette(),
  toggleCommandPalette: () => useUIStore.getState().toggleCommandPalette(),
  setActiveSettingsSection: (section: SettingsSection) =>
    useUIStore.getState().setActiveSettingsSection(section),
  closeAllModals: () => useUIStore.getState().closeAllModals(),
};

import type { LucideIcon } from "lucide-react";
import {
  Plus,
  FolderOpen,
  GitBranch,
  GitPullRequest,
  Settings,
  Sparkles,
  Puzzle,
} from "lucide-react";
import { uiActions } from "@/shared/stores/uiStore";
import { capabilities } from "@/platform/capabilities";

export type CommandGroup = "workspace" | "project" | "navigation" | "settings";

export interface CommandDefinition {
  id: string;
  label: string;
  icon: LucideIcon;
  group: CommandGroup;
  shortcut?: string;
  keywords?: string[];
  action: () => void;
  /** Return false to hide this command from the palette */
  when?: () => boolean;
}

export const GROUP_LABELS: Record<CommandGroup, string> = {
  workspace: "Workspace",
  project: "Project",
  navigation: "Navigation",
  settings: "Settings",
};

/**
 * Centralized command registry.
 *
 * Commands that need runtime context (native dialogs, mutations, etc.)
 * have placeholder actions here — the palette component overrides them
 * via the `actionOverrides` prop.
 */
export const staticCommands: CommandDefinition[] = [
  // --- Workspace ---
  {
    id: "new-workspace",
    label: "New Workspace",
    icon: Plus,
    group: "workspace",
    keywords: ["create", "add", "workspace", "agent"],
    action: () => uiActions.openNewWorkspaceModal(),
  },
  {
    id: "new-workspace-from",
    label: "New Workspace from\u2026",
    icon: GitPullRequest,
    group: "workspace",
    keywords: ["create", "pr", "pull request", "branch", "github", "from"],
    action: () => {},
  },

  // --- Project ---
  {
    id: "open-project",
    label: "Open Project",
    icon: FolderOpen,
    group: "project",
    keywords: ["add", "repository", "folder", "directory", "repo"],
    when: () => capabilities.nativeFolderPicker,
    action: () => {},
  },
  {
    id: "clone-repository",
    label: "Clone Repository",
    icon: GitBranch,
    group: "project",
    keywords: ["git", "clone", "github", "repo"],
    action: () => {},
  },

  // --- Navigation ---
  {
    id: "go-to-settings",
    label: "Go to Settings",
    icon: Settings,
    group: "navigation",
    shortcut: "\u2318,",
    keywords: ["preferences", "config", "options"],
    action: () => uiActions.openSettings(),
  },

  // --- Settings sections ---
  {
    id: "settings-general",
    label: "Settings: General",
    icon: Settings,
    group: "settings",
    keywords: ["theme", "appearance", "name", "preferences"],
    action: () => {
      uiActions.openSettings();
      uiActions.setActiveSettingsSection("general");
    },
  },
  {
    id: "settings-ai",
    label: "Settings: AI",
    icon: Sparkles,
    group: "settings",
    keywords: ["model", "claude", "anthropic", "api", "key", "provider"],
    action: () => {
      uiActions.openSettings();
      uiActions.setActiveSettingsSection("ai");
    },
  },
  {
    id: "settings-extensions",
    label: "Settings: Extensions",
    icon: Puzzle,
    group: "settings",
    keywords: ["mcp", "servers", "commands", "agents", "hooks", "plugins"],
    action: () => {
      uiActions.openSettings();
      uiActions.setActiveSettingsSection("extensions");
    },
  },
];

